// Mock implementations for timeout and error testing

type MockGitProvider struct {
	CreateMRError error
	MRResult      *provider.MRResult
}

func (m *MockGitProvider) CreateOrUpdateMR(ctx context.Context, config provider.MRConfig) (*provider.MRResult, error) {
	if m.CreateMRError != nil {
		return nil, m.CreateMRError
	}
	if m.MRResult != nil {
		return m.MRResult, nil
	}
	return &provider.MRResult{
		MRURL:   "https://gitlab.com/test/repo/-/merge_requests/123",
		MRURL:    123,
		Created: true,
	}, nil
}

func (m *MockGitProvider) ValidateConfiguration() error {
	return nil
}

type MockBuildChecker struct {
	BuildResult   *common.DeployResult
	BuildError    error
	CheckDelay    time.Duration // Simulate slow build checks
}

func (m *MockBuildChecker) CheckBuild(ctx context.Context, config common.DeployConfig) (*common.DeployResult, error) {
	if m.CheckDelay > 0 {
		select {
		case <-time.After(m.CheckDelay):
		case <-ctx.Done():
			return nil, ctx.Err()
		}
	}

	if m.BuildError != nil {
		return nil, m.BuildError
	}

	if m.BuildResult != nil {
		return m.BuildResult, nil
	}

	// Default: build fails
	return &common.DeployResult{Success: false, Message: "build failed"}, nil
}

